import React from 'react';
import { useUndoRedo } from './useUndoRedo';
import './styles.css';

export default function App() {
  const { state, set, undo, redo, canUndo, canRedo, reset, history } = useUndoRedo(0);

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useUndoRedo</h1>
      <p className="undo-value">Value: <strong data-testid="current">{state}</strong></p>
      <p className="undo-history">History: <span data-testid="history-length">{history.past.length}</span> past, <span>{history.future.length}</span> future</p>
      <div className="undo-actions">
        <button onClick={() => set(state + 1)}>+1</button>
        <button onClick={() => set(state + 10)}>+10</button>
        <button data-testid="undo" onClick={undo} disabled={!canUndo}>Undo</button>
        <button data-testid="redo" onClick={redo} disabled={!canRedo}>Redo</button>
        <button data-testid="reset" onClick={() => reset()}>Reset</button>
      </div>
    </div>
  );
}

import { useReducer, useCallback, useMemo } from 'react';

interface History<T> {
  past: T[];
  present: T;
  future: T[];
}

interface UndoRedoReturn<T> {
  state: T;
  set: (value: T) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  reset: (value?: T) => void;
  history: History<T>;
}

/**
 * Custom hook providing undo/redo history management.
 *
 * @param initialValue - The starting value
 * @returns Object with state, set, undo, redo, canUndo, canRedo, reset, history
 */
export function useUndoRedo<T>(initialValue: T): UndoRedoReturn<T> {
  // TODO: Define action types (SET, UNDO, REDO, RESET)
  // TODO: Implement the reducer that manages { past, present, future }
  // TODO: Wire up useReducer and derive the return value

  return {
    state: initialValue,
    set: () => {},
    undo: () => {},
    redo: () => {},
    canUndo: false,
    canRedo: false,
    reset: () => {},
    history: { past: [], present: initialValue, future: [] },
  };
}

.undo-value {
  font-size: 1.25rem;
  margin-bottom: 0.25rem;
}

.undo-value strong {
  color: #3b82f6;
  font-variant-numeric: tabular-nums;
}

.undo-history {
  font-size: 0.8125rem;
  color: #9ca3af;
  margin-bottom: 1rem;
}

.undo-actions {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.undo-actions button {
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
  transition: background 0.15s ease;
}

.undo-actions button:hover:not(:disabled) {
  background: #e5e7eb;
}

.undo-actions button:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

