import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useUndoRedo } from './useUndoRedo';

function Harness({ initial = 0 }: { initial?: number }) {
  const { state, set, undo, redo, canUndo, canRedo, reset, history } = useUndoRedo(initial);
  return (
    <div>
      <span data-testid="current">{state}</span>
      <span data-testid="history-length">{history.past.length}</span>
      <span data-testid="future-length">{history.future.length}</span>
      <button data-testid="set-5" onClick={() => set(5)}>Set 5</button>
      <button data-testid="set-10" onClick={() => set(10)}>Set 10</button>
      <button data-testid="set-15" onClick={() => set(15)}>Set 15</button>
      <button data-testid="undo" onClick={undo} disabled={!canUndo}>Undo</button>
      <button data-testid="redo" onClick={redo} disabled={!canRedo}>Redo</button>
      <button data-testid="reset" onClick={() => reset()}>Reset</button>
    </div>
  );
}

describe('useUndoRedo', () => {
  it('starts with the initial value', () => {
    render(<Harness initial={42} />);
    expect(screen.getByTestId('current')).toHaveTextContent('42');
  });

  it('cannot undo or redo initially', () => {
    render(<Harness />);
    expect(screen.getByTestId('undo')).toBeDisabled();
    expect(screen.getByTestId('redo')).toBeDisabled();
  });

  it('set pushes to history and updates state', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    expect(screen.getByTestId('current')).toHaveTextContent('5');
    expect(screen.getByTestId('history-length')).toHaveTextContent('1');
  });

  it('undo reverts to the previous value', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    fireEvent.click(screen.getByTestId('set-10'));
    fireEvent.click(screen.getByTestId('undo'));
    expect(screen.getByTestId('current')).toHaveTextContent('5');
    expect(screen.getByTestId('future-length')).toHaveTextContent('1');
  });

  it('redo re-applies the undone value', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    fireEvent.click(screen.getByTestId('undo'));
    fireEvent.click(screen.getByTestId('redo'));
    expect(screen.getByTestId('current')).toHaveTextContent('5');
    expect(screen.getByTestId('redo')).toBeDisabled();
  });

  it('set after undo clears the redo stack', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    fireEvent.click(screen.getByTestId('set-10'));
    fireEvent.click(screen.getByTestId('undo'));
    expect(screen.getByTestId('future-length')).toHaveTextContent('1');
    fireEvent.click(screen.getByTestId('set-15'));
    expect(screen.getByTestId('future-length')).toHaveTextContent('0');
    expect(screen.getByTestId('redo')).toBeDisabled();
  });

  it('reset clears all history', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    fireEvent.click(screen.getByTestId('set-10'));
    fireEvent.click(screen.getByTestId('reset'));
    expect(screen.getByTestId('current')).toHaveTextContent('0');
    expect(screen.getByTestId('history-length')).toHaveTextContent('0');
    expect(screen.getByTestId('future-length')).toHaveTextContent('0');
    expect(screen.getByTestId('undo')).toBeDisabled();
    expect(screen.getByTestId('redo')).toBeDisabled();
  });

  it('multiple undo/redo operations work correctly', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-5'));
    fireEvent.click(screen.getByTestId('set-10'));
    fireEvent.click(screen.getByTestId('set-15'));
    fireEvent.click(screen.getByTestId('undo'));
    fireEvent.click(screen.getByTestId('undo'));
    expect(screen.getByTestId('current')).toHaveTextContent('5');
    fireEvent.click(screen.getByTestId('redo'));
    expect(screen.getByTestId('current')).toHaveTextContent('10');
  });
});

