import { useReducer, useCallback, useMemo } from 'react';

interface History<T> {
  past: T[];
  present: T;
  future: T[];
}

type Action<T> =
  | { type: 'SET'; value: T }
  | { type: 'UNDO' }
  | { type: 'REDO' }
  | { type: 'RESET'; value: T };

function reducer<T>(state: History<T>, action: Action<T>): History<T> {
  switch (action.type) {
    case 'SET':
      return {
        past: [...state.past, state.present],
        present: action.value,
        future: [],
      };
    case 'UNDO': {
      if (state.past.length === 0) return state;
      const previous = state.past[state.past.length - 1];
      return {
        past: state.past.slice(0, -1),
        present: previous,
        future: [state.present, ...state.future],
      };
    }
    case 'REDO': {
      if (state.future.length === 0) return state;
      const next = state.future[0];
      return {
        past: [...state.past, state.present],
        present: next,
        future: state.future.slice(1),
      };
    }
    case 'RESET':
      return { past: [], present: action.value, future: [] };
    default:
      return state;
  }
}

interface UndoRedoReturn<T> {
  state: T;
  set: (value: T) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  reset: (value?: T) => void;
  history: History<T>;
}

export function useUndoRedo<T>(initialValue: T): UndoRedoReturn<T> {
  const [history, dispatch] = useReducer(reducer as React.Reducer<History<T>, Action<T>>, {
    past: [],
    present: initialValue,
    future: [],
  });

  const set = useCallback((value: T) => dispatch({ type: 'SET', value }), []);
  const undo = useCallback(() => dispatch({ type: 'UNDO' }), []);
  const redo = useCallback(() => dispatch({ type: 'REDO' }), []);
  const reset = useCallback(
    (value?: T) => dispatch({ type: 'RESET', value: value ?? initialValue }),
    [initialValue]
  );

  return {
    state: history.present,
    set,
    undo,
    redo,
    canUndo: history.past.length > 0,
    canRedo: history.future.length > 0,
    reset,
    history,
  };
}
